const d = msg.payload;

flow.set('last_weight_g',     d.weight_g     || 0);
flow.set('last_pct_drainage', d.pct_drainage || 0);
flow.set('last_ec',           d.ec_mscm      || 0);
flow.set('last_ph',           d.ph           || 0);
flow.set('last_input_mL',     d.input_mL     || 0);
flow.set('last_drainage_mL',  d.drainage_mL  || 0);
flow.set('last_temp',         d.temp         || 0);
flow.set('pump_state',        d.pump         || 'OFF');
flow.set('drain_pump_state',  d.drain_pump   || 'OFF');

node.status({ fill:'blue', shape:'dot',
    text: `drain:${d.pct_drainage}% EC:${d.ec_mscm} w:${d.weight_g}g` });

return msg;

const active       = flow.get('irrigation_active') || false;
const waitingRepos = flow.get('waiting_for_repos') || false;
const dayDone      = flow.get('day_done')          || false;

if (!active) {
    node.status({ fill:'grey', shape:'ring', text:'Not active — waiting morning check' });
    return null;
}
if (dayDone) {
    node.status({ fill:'green', shape:'ring', text:'Day complete — no more tours' });
    return null;
}
if (waitingRepos) {
    node.status({ fill:'yellow', shape:'ring', text:'In repos — waiting for timer...' });
    return null;
}

node.status({ fill:'green', shape:'dot', text:'✅ Passing to scheduler' });
return msg;

const pct    = msg.payload.pct_drainage;
const ec     = msg.payload.ec_mscm;
const tour   = (flow.get('tour_count') || 0) + 1;
const EC_MAX = 5.0;
const TEST_MODE = true;

if (pct >= 20 && tour > 8) {
    flow.set('weight_lastEvening', msg.payload.weight_g);
    flow.set('tour_count', 0);
    flow.set('irrigation_active', false);
    flow.set('waiting_for_repos', false);
    flow.set('day_done', true);
    node.status({ fill:'green', shape:'ring',
        text: `Day done — tour ${tour} — weight saved ${msg.payload.weight_g}g` });
    return [null, { payload: {
        action: 'STOP_DAY',
        timestamp: new Date().toISOString()
    }}];
}

let duree, repos, zone;

if (TEST_MODE) {
    if (pct < 10)       { duree = 1; repos = 1; zone = 'Zone1 <10% [TEST]'; }
    else if (pct < 20)  { duree = 1; repos = tour <= 3 ? 1 : 2; zone = 'Zone2 10-20% [TEST]'; }
    else if (pct < 35)  { duree = 1; repos = 2; zone = 'Zone3 20-35% [TEST]'; }
    else {
        duree = 1;
        repos = ({6:2,7:2,8:2,9:2})[tour] || 2;
        zone = 'Zone4 >=35% [TEST]';
    }
} else {
    if (pct < 10)       { duree = 15; repos = 1; zone = 'Zone1 <10%'; }
    else if (pct < 20)  { duree = 10; repos = tour <= 3 ? 5 : 10; zone = 'Zone2 10-20%'; }
    else if (pct < 35)  { duree = 8;  repos = 15; zone = 'Zone3 20-35%'; }
    else {
        duree = 8;
        repos = ({6:19,7:24,8:29,9:34})[tour] || 34;
        zone = 'Zone4 >=35%';
    }
}

let ec_adj = '';
if (ec > EC_MAX) {
    if (!TEST_MODE) { duree = Math.max(5, duree - 1); ec_adj = ` (EC ${ec}>${EC_MAX} → -1min)`; }
    else            { ec_adj = ` (EC ${ec}>${EC_MAX} — no adj in TEST)`; }
}

flow.set('tour_count', tour);
flow.set('current_duree', duree);
flow.set('current_repos', repos);
flow.set('waiting_for_repos', true);

node.status({ fill:'green', shape:'dot',
    text: `Tour ${tour} | ${zone} | ${duree}min irr | ${repos}min repos${ec_adj}` });

msg.payload = {
    action: 'START_IRRIGATION',
    tour, zone,
    duree_min: duree,
    repos_min: repos,
    pct_drainage: pct,
    ec_mscm: ec,
    ec_adjusted: ec > EC_MAX,
    test_mode: TEST_MODE,
    timestamp: new Date().toISOString()
};

// Output 1 → pump chain | Output 2 → events storage
return [msg, { payload: { action: 'START_IRRIGATION', timestamp: msg.payload.timestamp } }];

const duree = msg.payload.duree_min || flow.get('current_duree');
const repos = msg.payload.repos_min || flow.get('current_repos');
const tour  = flow.get('tour_count');

msg._duree_min = duree;
msg._repos_min = repos;
msg._tour      = tour;
msg.payload    = { id: 'abdellah', pump: 1 };

node.status({ fill:'green', shape:'dot', text: `Pump ON — ${duree}min tour ${tour}` });
return msg;

const duree_min = msg._duree_min || flow.get('current_duree') || 1;
const repos_min = msg._repos_min || flow.get('current_repos') || 1;
const tour      = msg._tour      || flow.get('tour_count')    || 1;
const startedAt = Date.now();

const old = context.get('pumpOffTimer');
if (old) clearInterval(old);

node.status({ fill:'yellow', shape:'dot', text: `💧 Pump ON — ${duree_min}min | tour ${tour}` });

const tick = setInterval(() => {
    const elapsed_s   = Math.floor((Date.now() - startedAt) / 1000);
    const remaining_s = Math.max(0, duree_min * 60 - elapsed_s);
    const mins        = Math.floor(remaining_s / 60);
    const secs        = remaining_s % 60;
    const pct_done    = Math.min(100, Math.round((elapsed_s / (duree_min * 60)) * 100));

    node.send([null, {
        payload: {
            type: 'irrigation', remaining_s, elapsed_s,
            total_s: duree_min * 60, pct_done,
            fmt: `${mins}:${String(secs).padStart(2,'0')}`,
            pump: 'ON', tour
        }
    }]);

    node.status({ fill:'green', shape:'dot',
        text: `💧 ${mins}:${String(secs).padStart(2,'0')} left | tour ${tour}` });

    if (remaining_s <= 0) {
        clearInterval(tick);
        context.set('pumpOffTimer', null);
        node.status({ fill:'red', shape:'ring', text: `Pump OFF — starting repos ${repos_min}min` });

        node.send([{ topic: 'pump_off', payload: { id: 'abdellah', pump: 0 } }, null]);
        setTimeout(() => {
            node.send([{
                topic: 'repos_start',
                payload: { action: 'IRRIGATION_DONE', tour, repos_min, timestamp: new Date().toISOString() }
            }, null]);
        }, 500);
    }
}, 1000);

context.set('pumpOffTimer', tick);
return null;

const now = Date.now();
const last = context.get('lastSent') || 0;
if (now - last < 5000) return null;
context.set('lastSent', now);
return msg;

if (msg.topic === 'pump_off') {
    node.status({ fill:'red', shape:'dot', text:'Pump OFF → HTTP' });
    return [msg, null];
} else if (msg.topic === 'repos_start') {
    node.status({ fill:'blue', shape:'dot', text:'Repos start → timer' });
    return [null, msg];
}
return null;

const repos_min = msg.payload.repos_min || flow.get('current_repos') || 1;
const tour      = msg.payload.tour      || flow.get('tour_count')    || 1;
const startedAt = Date.now();

const old = context.get('reposTimer');
if (old) clearInterval(old);

node.status({ fill:'grey', shape:'ring', text: `⏳ Repos ${repos_min}min — after tour ${tour}` });

// Emit REPOS_START event immediately
node.send([{ payload: {
    action: 'REPOS_START',
    timestamp: new Date().toISOString()
}}, null]);

const tick = setInterval(() => {
    const elapsed_s   = Math.floor((Date.now() - startedAt) / 1000);
    const remaining_s = Math.max(0, repos_min * 60 - elapsed_s);
    const mins        = Math.floor(remaining_s / 60);
    const secs        = remaining_s % 60;
    const pct_done    = Math.min(100, Math.round((elapsed_s / (repos_min * 60)) * 100));

    node.send([null, {
        payload: {
            type: 'repos', remaining_s, elapsed_s,
            total_s: repos_min * 60, pct_done,
            fmt: `${mins}:${String(secs).padStart(2,'0')}`,
            pump: 'OFF', tour, next_tour: tour + 1
        }
    }]);

    node.status({ fill:'yellow', shape:'ring',
        text: `⏳ ${mins}:${String(secs).padStart(2,'0')} → tour ${tour + 1}` });

    if (remaining_s <= 0) {
        clearInterval(tick);
        context.set('reposTimer', null);
        flow.set('waiting_for_repos', false);
        node.status({ fill:'blue', shape:'dot', text: `✅ Repos done — tour ${tour + 1} ready` });
        // Emit REPOS_DONE event
        node.send([{ payload: {
            action: 'REPOS_DONE',
            timestamp: new Date().toISOString()
        }}, null]);
    }
}, 1000);

context.set('reposTimer', tick);
return null;

const now = Date.now();
const last = context.get('lastSent') || 0;
if (now - last < 5000) return null;
context.set('lastSent', now);
return msg;

const drainage_mL  = msg.payload.drainage_mL || 0;
const THRESHOLD_ML = 5000;
const drainRunning = flow.get('drain_pump_running') || false;

if (drainage_mL >= THRESHOLD_ML && !drainRunning) {
    flow.set('drain_pump_running', true);
    node.status({ fill:'blue', shape:'dot',
        text: `🚰 Drain ON — ${drainage_mL}mL >= ${THRESHOLD_ML}mL` });
    return [{ payload: { id: 'abdellah', drain_pump: 1 } }, null];
}

node.status({ fill:'grey', shape:'ring',
    text: `drain: ${drainage_mL}mL` });
return null;

const DRAIN_DURATION_MIN = 3;
const old = context.get('drainOffTimer');
if (old) clearTimeout(old);

node.status({ fill:'blue', shape:'dot',
    text: `🚰 Drain ON — auto OFF in ${DRAIN_DURATION_MIN}min` });

node.send({ payload: msg.payload });

const timer = setTimeout(() => {
    context.set('drainOffTimer', null);
    flow.set('drain_pump_running', false);
    node.status({ fill:'grey', shape:'ring', text:'🚰 Drain pump OFF' });
    node.send({ payload: { id: 'abdellah', drain_pump: 0 } });
}, DRAIN_DURATION_MIN * 60 * 1000);

context.set('drainOffTimer', timer);
return null;

const weightEvening = flow.get('weight_lastEvening') || null;
const weightMorning  = flow.get('last_weight_g')     || null;

if (!weightEvening || !weightMorning) {
    node.warn('No reference weight yet — skipping morning check');
    node.status({ fill:'yellow', shape:'ring', text:'No reference weight' });
    return null;
}

const delta = weightEvening - weightMorning;
const threshold = weightEvening * 0.05;
const shouldIrrigate = delta >= threshold;

node.status({
    fill: shouldIrrigate ? 'green' : 'grey', shape: 'dot',
    text: `Δ=${delta}g | thr=${Math.round(threshold)}g | ${shouldIrrigate ? 'START' : 'WAIT'}`
});

msg.payload = {
    weight_evening_g: weightEvening,
    weight_morning_g: weightMorning,
    delta_g: delta,
    threshold_g: Math.round(threshold),
    should_irrigate: shouldIrrigate,
    timestamp: new Date().toISOString()
};
return msg;

flow.set('tour_count', 0);
flow.set('irrigation_active', true);
flow.set('waiting_for_repos', false);
flow.set('day_done', false);

node.status({ fill:'green', shape:'dot', text:'Day started — gate open' });
msg.payload = { action: 'DAY_STARTED', timestamp: new Date().toISOString() };
return msg;
